1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return an empty set when there are no living cells", () => {
6	    expect(nextGeneration(new Set())).toEqual(new Set());
7	  });
8	  it("should kill a single living cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration(new Set(["0,0"]))).toEqual(new Set());
10	  });
11	  it("should kill a living cell with only one living neighbor (underpopulation)", () => {
12	    expect(nextGeneration(new Set(["0,0", "1,0"]))).toEqual(new Set());
13	  });
14	  it("should keep a living cell alive with two living neighbors", () => {
15	    // Three cells in a row: (0,0), (1,0), (2,0)
16	    // Middle cell (1,0) has 2 neighbors: (0,0) and (2,0) -> stays alive
17	    // (0,0) has 1 neighbor -> dies
18	    // (2,0) has 1 neighbor -> dies
19	    // Dead cells (1,1) and (1,-1) each have 3 neighbors -> become alive
20	    expect(nextGeneration(new Set(["0,0", "1,0", "2,0"]))).toEqual(
21	      new Set(["1,0", "1,1", "1,-1"])
22	    );
23	  });
24	  it("should keep a living cell alive with three living neighbors", () => {
25	    // 2x2 block: each cell has exactly 3 living neighbors -> all stay alive
26	    // No dead cell has exactly 3 neighbors, so no new cells are born
27	    expect(nextGeneration(new Set(["0,0", "1,0", "0,1", "1,1"]))).toEqual(
28	      new Set(["0,0", "1,0", "0,1", "1,1"])
29	    );
30	  });
31	  it("should kill a living cell with four living neighbors (overpopulation)", () => {
32	    // Plus shape: center (1,1) with four neighbors at (0,1), (2,1), (1,0), (1,2)
33	    // Center cell has exactly 4 living neighbors -> dies (overpopulation)
34	    const result = nextGeneration(new Set(["1,1", "0,1", "2,1", "1,0", "1,2"]));
35	    expect(result.has("1,1")).toBe(false);
36	  });
37	  it("should bring a dead cell to life when it has exactly three living neighbors (reproduction)", () => {
38	    // Three cells in an L-shape: (0,0), (1,0), (0,1)
39	    // Dead cell (1,1) has 3 living neighbors: (0,0), (1,0), (0,1) -> becomes alive
40	    const result = nextGeneration(new Set(["0,0", "1,0", "0,1"]));
41	    expect(result.has("1,1")).toBe(true);
42	  });
43	  it("should not bring a dead cell to life when it has two living neighbors", () => {
44	    // Three cells in a row: (0,0), (1,0), (2,0)
45	    // Dead cell (2,1) has exactly 2 living neighbors: (1,0) and (2,0)
46	    // It should NOT become alive (reproduction requires exactly 3 neighbors)
47	    const result = nextGeneration(new Set(["0,0", "1,0", "2,0"]));
48	    expect(result.has("2,1")).toBe(false);
49	  });
50	  it.todo("should handle living cells with negative coordinates");
51	});
